6830292,-0.02473118,0.05101836,0.04434782,-0.00840446,0.02040713,0.06235232,0.03612574,-0.03843446,0.00758361,0.03931096,-0.00323839,0.01261263,-0.01174045,0.02470809,0.01950139,-0.02614059,-0.03255459,-0.02287416,0.05626896,0.02014558,-0.05605428,0.03181088,-0.01441151,-0.05108352,-0.08060431,-0.03604213,-0.01552911,-0.02595395,0.01928203,-0.01826297,0.01016545,0.01639562,0.05999425,0.02155242,0.00388209,0.00849482,-0.02910852,0.03895691,-0.05705848,0.10547836,-0.00695070,0.00288665]',E'use rocket::get;\n\nuse rocket::tokio::time::{Duration, interval};\nuse rocket::response::stream::TextStream;\n\n/// Produce an infinite series of `"hello"`s, one per second.\n#[get("/infinite-hellos")]\nfn hello() -> TextStream![&''static str] {\n    TextStream! {\n        let mut interval = interval(Duration::from_secs(1));\n        loop {\n            yield "hello";\n            interval.tick().await;\n        }\n    }\n}\n```\n\nSee the [`stream`] docs for full details on creating streams including notes on\nhow to detect and handle graceful shutdown requests.\n\n[`stream`]: @api/rocket/response/stream/index.html\n[`stream!`]: @api/rocket/response/stream/macro.stream.html\n[async `Stream`]: https://docs.rs/futures/0.3/futures/stream/trait.Stream.html\n[`ReaderStream`]: @api/rocket/response/stream/struct.ReaderStream.html\n[`TextStream`]: @api/rocket/response/stream/struct.TextStream.html\n[`EventStream`]: @api/rocket/response/stream/struct.EventStream.html\n[`chat` example]: @example/chat','{"source": "rocket", "version": "0.6", "language": "rust", "title": "Responses", "section_title": "5-responses", "url": "https://github.com/rwf2/Rocket/blob/v0.5-rc/site/guide/5-responses.md", "topics": "rocket,http,5,responses", "categories": "web,rust,rest"}');
