15418,0.16557972,0.03070313,-0.01061155,0.00368505,-0.03295681,0.02998480,0.05102408,0.09338543,-0.01745806,-0.01634924,0.04884453,0.00632579,0.04807316,0.01955877,0.01624525,0.04329827,0.00512624,-0.01300863,-0.05553695,0.03629101,-0.01790395,-0.05644611,-0.00745205,-0.06950881,-0.00371913,-0.02630809,-0.02971705,-0.06181051,0.02539838,0.06443942,-0.06586216,-0.03343829,0.02263298,0.01600792,-0.00676271,-0.01160800,-0.01241361,0.00914424,0.00806073,-0.00599248,0.05503071,-0.05316136,0.05368574]',E'#[macro_use] extern crate rocket;\n\nuse rocket_dyn_templates::Template;\n\n#[launch]\nfn rocket() -> _ {\n    rocket::build()\n        .mount("/", routes![/* .. */])\n        .attach(Template::fairing())\n}\n```\n\nRocket discovers templates in the [configurable] `template_dir` directory.\nTemplating support in Rocket is engine agnostic. The engine used to render a\ntemplate depends on the template file''s extension. For example, if a file ends\nwith `.hbs`, Handlebars is used, while if a file ends with `.tera`, Tera is\nused.\n\n! note: The name of the template _does not_ include its extension.\n\n  For a template file named `index.html.tera`, call `render("index")` and use\n  the name `"index"` in templates, i.e, `{% extends "index" %}` or `{% extends\n  "base" %}` for `base.html.tera`.\n\n[`context!`]: @api/rocket_dyn_templates/macro.context.html','{"source": "rocket", "version": "0.6", "language": "rust", "title": "Responses", "section_title": "5-responses", "url": "https://github.com/rwf2/Rocket/blob/v0.5-rc/site/guide/5-responses.md", "topics": "rocket,http,5,responses", "categories": "web,rust,rest"}');
